   1→/**
   2→ * 考试系统 - 全量接口测试脚本
   3→ *
   4→ * 用法: node test-api.js
   5→ * 要求: Node.js 18+（原生 fetch）
   6→ * 前置: 后端以 dev profile 启动（start-backend.bat）
   7→ *
   8→ * 覆盖 27 个接口，13 个测试维度
   9→ */
  10→
  11→const crypto = require('crypto');
  12→
  13→// ========== 配置 ==========
  14→const CONFIG = {
  15→  host: 'http://localhost:18080',
  16→  frontendUrl: 'http://localhost:5173',
  17→  jwtSecret: 'YmFzZTY0LWVuY29kZWQtc2VjcmV0LWtleS1mb3ItZXhhbS1zeXN0ZW0tand0',
  18→  mockUserCount: 20,
  19→};
  20→
  21→// ========== 测试框架 ==========
  22→let passed = 0;
  23→let failed = 0;
  24→let token = '';
  25→
  26→function assert(name, condition, detail) {
  27→  if (condition) {
  28→    console.log(`  ✅ ${name}`);
  29→    passed++;
  30→  } else {
  31→    console.log(`  ❌ ${name}`);
  32→    if (detail !== undefined)
  33→      console.log(`     实际值:`, typeof detail === 'object'
  34→        ? JSON.stringify(detail).slice(0, 300) : detail);
  35→    failed++;
  36→  }
  37→}
  38→
  39→// ========== HTTP 工具 ==========
  40→async function rawFetch(method, url, body) {
  41→  const headers = { 'content-type': 'application/json' };
  42→  if (token) headers['authorization'] = `Bearer ${token}`;
  43→
  44→  const opts = { method, headers, redirect: 'manual' };
  45→  if (body !== undefined) opts.body = JSON.stringify(body);
  46→  return fetch(url, opts);
  47→}
  48→
  49→async function GET(path) {
  50→  const res = await rawFetch('GET', `${CONFIG.host}${path}`);
  51→  return res.json();
  52→}
  53→
  54→async function POST(path, body) {
  55→  const res = await rawFetch('POST', `${CONFIG.host}${path}`, body);
  56→  return res.json();
  57→}
  58→
  59→async function PUT(path, body) {
  60→  const res = await rawFetch('PUT', `${CONFIG.host}${path}`, body);
  61→  return res.json();
  62→}
  63→
  64→async function DEL(path, body) {
  65→  const res = await rawFetch('DELETE', `${CONFIG.host}${path}`, body);
  66→  return res.json();
  67→}
  68→
  69→// ========== 登录管理 ==========
  70→async function login() {
  71→  console.log('🔑 通过 dev profile 获取 JWT ...');
  72→  const res = await rawFetch('GET', `${CONFIG.host}/api/auth/oauth2/login`);
  73→  const location = res.headers.get('location');
  74→  if (!location || !location.includes('token=')) {
  75→    console.log('❌ 登录失败: 未获取到 redirect location', location);
  76→    process.exit(1);
  77→  }
  78→  token = new URL(location).searchParams.get('token');
  79→  console.log(`   ✅ 登录成功, token=${token.substring(0, 20)}...\n`);
  80→}
  81→
  82→let savedToken = '';
  83→function saveSession() { savedToken = token; }
  84→function restoreSession() { token = savedToken; }
  85→
  86→// ========== 测试数据追踪 ==========
  87→let testExamId = null;        // 测试创建的试卷 ID
  88→let testQuestionIds = [];     // 测试创建的题目 ID 列表
  89→let testRecordId = null;      // 考试记录 ID
