  91→// ========== 维度 1: 正常流程 — 管理员 CRUD ==========
  92→async function testAdminExamCrud() {
  93→  console.log('📋 1. 管理员试卷 CRUD');
  94→
  95→  // 创建试卷
  96→  const createRes = await POST('/api/admin/exams', {
  97→    title: '自动化测试试卷_' + Date.now(),
  98→    timeLimitMin: 30,
  99→    showAnswer: true,
 100→    showAnalysis: true,
 101→    questionCount: 0,
 102→    maxAttempts: 3,
 103→    accessMode: 'open',
 104→  });
 105→  assert('创建试卷 code=200', createRes.code === 200, createRes);
 106→  assert('返回 data.id', createRes.data?.id != null, createRes.data);
 107→  assert('返回 data.status=draft', createRes.data?.status === 'draft', createRes.data?.status);
 108→  testExamId = createRes.data?.id;
 109→
 110→  // 查询列表
 111→  const listRes = await GET('/api/admin/exams?page=1&size=10');
 112→  assert('列表 code=200', listRes.code === 200, listRes);
 113→  assert('列表含 records 数组', Array.isArray(listRes.data?.records), listRes.data);
 114→  assert('列表含 total', typeof listRes.data?.total === 'number', listRes.data?.total);
 115→
 116→  if (listRes.data?.records?.length > 0) {
 117→    const first = listRes.data.records[0];
 118→    assert('记录含 id', first.id != null);
 119→    assert('记录含 title (string)', typeof first.title === 'string');
 120→    assert('记录含 status', first.status != null);
 121→    assert('记录含 questionCount', typeof first.questionCount === 'number');
 122→    assert('记录含 respondentCount', typeof first.respondentCount === 'number');
 123→  }
 124→
 125→  // 更新试卷
 126→  const updateRes = await PUT(`/api/admin/exams/${testExamId}`, {
 127→    title: '更新后的试卷_' + Date.now(),
 128→    timeLimitMin: 60,
 129→    showAnswer: false,
 130→    showAnalysis: false,
 131→    questionCount: 2,
 132→    maxAttempts: 5,
 133→    accessMode: 'whitelist',
 134→  });
 135→  assert('更新试卷 code=200', updateRes.code === 200, updateRes);
 136→}
