 138→// ========== 维度 1: 正常流程 — 题目 CRUD ==========
 139→async function testQuestionCrud() {
 140→  console.log('\n📋 1b. 题目 CRUD');
 141→
 142→  // 先把试卷改回 open + draft（update 要求 draft 状态）
 143→  await PUT(`/api/admin/exams/${testExamId}`, {
 144→    title: '测试试卷_含题目_' + Date.now(),
 145→    timeLimitMin: 30,
 146→    showAnswer: true,
 147→    showAnalysis: true,
 148→    questionCount: 0,
 149→    maxAttempts: 0,
 150→    accessMode: 'open',
 151→  });
 152→
 153→  // 创建单个题目
 154→  const q1 = await POST(`/api/admin/exams/${testExamId}/questions`, {
 155→    content: '1+1=?',
 156→    optionA: '1',
 157→    optionB: '2',
 158→    optionC: '3',
 159→    optionD: '4',
 160→    correctAnswer: 'B',
 161→    analysis: '基础数学',
 162→  });
 163→  assert('创建题目 code=200', q1.code === 200, q1);
 164→  assert('返回 questionId', q1.data?.id != null, q1.data);
 165→  testQuestionIds.push(q1.data?.id);
 166→
 167→  // 批量导入题目
 168→  const batchRes = await POST(`/api/admin/exams/${testExamId}/questions/batch`, {
 169→    questions: [
 170→      { content: '2+2=?', optionA: '3', optionB: '4', optionC: '5', optionD: '6', correctAnswer: 'B', analysis: '加法' },
 171→      { content: '3+3=?', optionA: '5', optionB: '6', optionC: '7', optionD: '8', correctAnswer: 'B', analysis: '加法' },
 172→    ],
 173→  });
 174→  assert('批量导入 code=200', batchRes.code === 200, batchRes);
 175→  assert('批量导入返回数量=2', batchRes.data === 2, batchRes.data);
 176→
 177→  // 查询题目列表
 178→  const listQ = await GET(`/api/admin/exams/${testExamId}/questions`);
 179→  assert('题目列表 code=200', listQ.code === 200, listQ);
 180→  assert('题目列表是数组', Array.isArray(listQ.data), listQ.data);
 181→  assert('题目数量>=3', listQ.data?.length >= 3, listQ.data?.length);
 182→
 183→  // 记录所有题目 ID
 184→  if (listQ.data) {
 185→    testQuestionIds = listQ.data.map(q => q.id);
 186→  }
 187→
 188→  // 更新题目
 189→  const updateQ = await PUT(`/api/admin/questions/${testQuestionIds[0]}`, {
 190→    content: '更新后: 1+1=?',
 191→    optionA: '0',
 192→    optionB: '2',
 193→    optionC: '3',
 194→    optionD: '4',
 195→    correctAnswer: 'B',
 196→    analysis: '更新后的解析',
 197→  });
 198→  assert('更新题目 code=200', updateQ.code === 200, updateQ);
 199→}
