 201→// ========== 维度 1: 正常流程 — 试卷状态流转 ==========
 202→async function testExamStatusFlow() {
 203→  console.log('\n📋 1c. 试卷状态流转');
 204→
 205→  // draft -> published
 206→  const pub = await PUT(`/api/admin/exams/${testExamId}/publish`);
 207→  assert('发布试卷 code=200', pub.code === 200, pub);
 208→
 209→  // published -> unpublish -> draft
 210→  const unpub = await PUT(`/api/admin/exams/${testExamId}/unpublish`);
 211→  assert('取消发布 code=200', unpub.code === 200, unpub);
 212→
 213→  // draft -> published (再次)
 214→  const pub2 = await PUT(`/api/admin/exams/${testExamId}/publish`);
 215→  assert('再次发布 code=200', pub2.code === 200, pub2);
 216→
 217→  // published -> closed
 218→  const close = await PUT(`/api/admin/exams/${testExamId}/close`);
 219→  assert('关闭试卷 code=200', close.code === 200, close);
 220→
 221→  // closed -> reopen -> published
 222→  const reopen = await PUT(`/api/admin/exams/${testExamId}/reopen`);
 223→  assert('重新发布 code=200', reopen.code === 200, reopen);
 224→
 225→  // 如果 reopen 失败，恢复到 published 状态以便后续测试
 226→  if (reopen.code !== 200) {
 227→    console.log('  ⚠️ reopen 失败(可能是后端 bug)，尝试用新试卷继续测试');
 228→    // 创建一个新的 published 试卷
 229→    const newExam = await POST('/api/admin/exams', {
 230→      title: '恢复测试_' + Date.now(),
 231→      timeLimitMin: 30,
 232→      showAnswer: true,
 233→      showAnalysis: true,
 234→      questionCount: 0,
 235→      maxAttempts: 0,
 236→      accessMode: 'open',
 237→    });
 238→    const newId = newExam.data?.id;
 239→    if (newId) {
 240→      // 添加题目
 241→      for (const q of [
 242→        { content: '恢复1+1=?', optionA: '1', optionB: '2', optionC: '3', optionD: '4', correctAnswer: 'B' },
 243→        { content: '恢复2+2=?', optionA: '3', optionB: '4', optionC: '5', optionD: '6', correctAnswer: 'B' },
 244→        { content: '恢复3+3=?', optionA: '5', optionB: '6', optionC: '7', optionD: '8', correctAnswer: 'B' },
 245→      ]) {
 246→        await POST(`/api/admin/exams/${newId}/questions`, q);
 247→      }
 248→      await PUT(`/api/admin/exams/${newId}/publish`);
 249→      // 获取新题目 ID
 250→      const ql = await GET(`/api/admin/exams/${newId}/questions`);
 251→      testQuestionIds = ql.data?.map(q => q.id) || [];
 252→      testExamId = newId;
 253→      console.log(`  ℹ️ 已切换到新试卷 ID=${newId}`);
 254→    }
 255→  }
 256→}
