 258→// ========== 维度 1: 正常流程 — 考生端考试 ==========
 259→async function testStudentExamFlow() {
 260→  console.log('\n📋 1d. 考生端考试流程');
 261→
 262→  // 考试列表
 263→  const exams = await GET('/api/exams?page=1&size=10');
 264→  assert('考试列表 code=200', exams.code === 200, exams);
 265→  assert('列表含 records', Array.isArray(exams.data?.records), exams.data);
 266→
 267→  // 考试详情
 268→  const detail = await GET(`/api/exams/${testExamId}`);
 269→  assert('考试详情 code=200', detail.code === 200, detail);
 270→  assert('详情含 title', typeof detail.data?.title === 'string', detail.data);
 271→  assert('详情含 status=published', detail.data?.status === 'published', detail.data?.status);
 272→  assert('详情含 remainingAttempts', detail.data?.remainingAttempts !== undefined);
 273→
 274→  // 开始考试
 275→  const start = await POST(`/api/exams/${testExamId}/start`);
 276→  assert('开始考试 code=200', start.code === 200, start);
 277→  assert('返回 recordId', start.data?.recordId != null, start.data);
 278→  assert('返回 questions 数组', Array.isArray(start.data?.questions), start.data);
 279→  assert('题目不含 correctAnswer', start.data?.questions?.[0]?.correctAnswer == null);
 280→  assert('题目不含 analysis', start.data?.questions?.[0]?.analysis == null);
 281→  testRecordId = start.data?.recordId;
 282→
 283→  // 构建答案
 284→  const answers = (start.data?.questions || []).map(q => ({
 285→    questionId: q.id,
 286→    answer: 'B',
 287→  }));
 288→
 289→  // 提交考试
 290→  const submit = await POST(`/api/exams/${testExamId}/submit`, {
 291→    recordId: testRecordId,
 292→    answers,
 293→  });
 294→  assert('提交考试 code=200', submit.code === 200, submit);
 295→  assert('返回 score', submit.data?.score != null, submit.data);
 296→  assert('返回 status', submit.data?.status != null, submit.data?.status);
 297→
 298→  // 考试记录列表
 299→  const records = await GET('/api/records?page=1&size=10');
 300→  assert('记录列表 code=200', records.code === 200, records);
 301→  assert('记录含 records', Array.isArray(records.data?.records));
 302→  assert('记录数量>=1', records.data?.records?.length >= 1);
 303→
 304→  if (records.data?.records?.length > 0) {
 305→    const rec = records.data.records[0];
 306→    assert('记录含 id', rec.id != null);
 307→    assert('记录含 examTitle', typeof rec.examTitle === 'string');
 308→    assert('记录含 score', rec.score != null);
 309→    assert('记录含 status', rec.status != null);
 310→    assert('记录含 attemptNo', rec.attemptNo != null);
 311→    assert('列表中 answers 为 null', rec.answers == null);
 312→  }
 313→
 314→  // 记录详情
 315→  const recordDetail = await GET(`/api/records/${testRecordId}`);
 316→  assert('记录详情 code=200', recordDetail.code === 200, recordDetail);
 317→  assert('详情含 answers 数组', Array.isArray(recordDetail.data?.answers), recordDetail.data);
 318→  if (recordDetail.data?.answers?.length > 0) {
 319→    const ans = recordDetail.data.answers[0];
 320→    assert('答题含 questionId', ans.questionId != null);
 321→    assert('答题含 userAnswer', ans.userAnswer != null);
 322→    assert('答题含 isCorrect', ans.isCorrect != null);
 323→    assert('答题含 content', typeof ans.content === 'string');
 324→    assert('showAnswer=true 时含 correctAnswer', ans.correctAnswer != null);
 325→    assert('showAnalysis=true 时含 analysis', ans.analysis != null);
 326→  }
 327→}
