 329→// ========== 维度 1: 正常流程 — 白名单 ==========
 330→async function testWhitelist() {
 331→  console.log('\n📋 1e. 白名单管理');
 332→
 333→  // 获取当前用户 ID
 334→  const me = await GET('/api/auth/me');
 335→  assert('获取当前用户 code=200', me.code === 200, me);
 336→  const myUserId = me.data?.id;
 337→
 338→  // 查询白名单（空）
 339→  const list1 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
 340→  assert('白名单列表 code=200', list1.code === 200, list1);
 341→  assert('初始白名单是数组', Array.isArray(list1.data));
 342→
 343→  // 添加白名单
 344→  const addRes = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myUserId] });
 345→  assert('添加白名单 code=200', addRes.code === 200, addRes);
 346→  assert('添加数量>=0', addRes.data >= 0, addRes.data);
 347→
 348→  // 再查白名单
 349→  const list2 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
 350→  assert('添加后白名单有记录', list2.data?.length > 0, list2.data?.length);
 351→
 352→  // 删除白名单
 353→  const removeRes = await DEL(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myUserId] });
 354→  assert('移除白名单 code=200', removeRes.code === 200, removeRes);
 355→
 356→  // 确认移除
 357→  const list3 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
 358→  const found = list3.data?.find(u => u.id === myUserId);
 359→  assert('移除后不在白名单中', !found);
 360→}
