 392→// ========== 维度 2: 分页边界 ==========
 393→async function testPaginationBoundary() {
 394→  console.log('\n📐 2. 分页边界');
 395→
 396→  // admin 列表
 397→  const p1 = await GET('/api/admin/exams?page=1&size=1');
