 446→// ========== 维度 4: 参数校验 ==========
 447→async function testParamValidation() {
 448→  console.log('\n🔒 4. 参数校验');
 449→
 450→  // 创建试卷缺少必填字段 title
 451→  const noTitle = await POST('/api/admin/exams', {
 452→    timeLimitMin: 30,
 453→    showAnswer: true,
 454→    showAnalysis: true,
 455→    questionCount: 0,
 456→    maxAttempts: 0,
 457→    accessMode: 'open',
 458→  });
 459→  assert('缺少 title 返回错误', noTitle.code !== 200, noTitle);
 460→
 461→  // 创建试卷空 title
 462→  const emptyTitle = await POST('/api/admin/exams', {
 463→    title: '',
 464→    timeLimitMin: 30,
 465→    showAnswer: true,
 466→    showAnalysis: true,
 467→    questionCount: 0,
 468→    maxAttempts: 0,
 469→    accessMode: 'open',
 470→  });
 471→  assert('空 title 返回错误', emptyTitle.code !== 200, emptyTitle);
 472→
 473→  // 创建试卷纯空格 title
 474→  const spaceTitle = await POST('/api/admin/exams', {
 475→    title: '   ',
 476→    timeLimitMin: 30,
 477→    showAnswer: true,
 478→    showAnalysis: true,
 479→    questionCount: 0,
 480→    maxAttempts: 0,
