1001→function generateJwt(userId, isAdmin) {
1002→  const key = Buffer.from(CONFIG.jwtSecret, 'base64');
1003→  const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
1004→  const now = Math.floor(Date.now() / 1000);
1005→  const payload = Buffer.from(JSON.stringify({
1006→    userId, isAdmin, iat: now, exp: now + 86400,
1007→  })).toString('base64url');
1008→  const sig = crypto.createHmac('sha256', key)
1009→    .update(`${header}.${payload}`).digest('base64url');
1010→  return `${header}.${payload}.${sig}`;
1011→}
