package com.exam.controller;

import com.exam.dto.Result;
import com.exam.dto.UserInfo;
import com.exam.service.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.env.Environment;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.util.UriComponentsBuilder;

import java.util.Arrays;

/**
 * 认证接口：OAuth2 登录、回调、获取当前用户
 */
@Slf4j
@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthService authService;
    private final Environment environment;

    @Value("${spring.security.oauth2.client.registration.default.client-id}")
    private String clientId;

    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
    private String authorizationUri;

    @Value("${spring.security.oauth2.client.registration.default.scope:openid,profile,email}")
    private String scope;

    @Value("${app.frontend-url:http://localhost:5173}")
    private String frontendUrl;

    public AuthController(AuthService authService, Environment environment) {
        this.authService = authService;
        this.environment = environment;
    }

    private boolean isDevProfile() {
        return Arrays.asList(environment.getActiveProfiles()).contains("dev");
    }

    /**
     * 构建 OA 授权地址并 302 重定向；dev 环境直接签发 JWT 跳回前端
     */
    @GetMapping("/oauth2/login")
    public ResponseEntity<Void> login(HttpServletRequest request) {
        if (isDevProfile()) {
            String token = authService.devLogin();
            String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
            log.info("[lbl][Auth][LOGIN] Dev 模式: 跳过 OAuth2, 直接重定向到前端");
            return ResponseEntity.status(HttpStatus.FOUND)
                    .header(HttpHeaders.LOCATION, callbackUrl)
                    .build();
        }

        String redirectUri = buildRedirectUri(request);

        String authorizeUrl = UriComponentsBuilder.fromHttpUrl(authorizationUri)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("response_type", "code")
                .queryParam("scope", scope)
                .toUriString();

        log.debug("[lbl][Auth][LOGIN] OAuth2 登录重定向: {}", authorizeUrl);

        return ResponseEntity.status(HttpStatus.FOUND)
                .header(HttpHeaders.LOCATION, authorizeUrl)
                .build();
    }

    /**
     * OAuth2 回调：用 code 换 token，302 重定向到前端并携带 token
     */
    @GetMapping("/oauth2/callback")
    public ResponseEntity<Void> callback(@RequestParam("code") String code,
                                         HttpServletRequest request) {
        String redirectUri = buildRedirectUri(request);
        String token = authService.handleOAuthCallback(code, redirectUri);
        log.info("[lbl][Auth][CALLBACK] OAuth2 回调完成, 已签发 token, 重定向到前端");

        String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
        return ResponseEntity.status(HttpStatus.FOUND)
                .header(HttpHeaders.LOCATION, callbackUrl)
                .build();
    }

    /**
     * 获取当前登录用户信息
     */
    @GetMapping("/me")
    public Result<UserInfo> me() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        Long userId = Long.parseLong(auth.getName());
        UserInfo userInfo = authService.getCurrentUser(userId);
        return Result.ok(userInfo);
    }

    /**
     * 根据当前请求构建 OAuth2 回调地址
     */
    private String buildRedirectUri(HttpServletRequest request) {
        String scheme = request.getScheme();
        String serverName = request.getServerName();
        int serverPort = request.getServerPort();

        StringBuilder sb = new StringBuilder();
        sb.append(scheme).append("://").append(serverName);
        // 非标准端口时拼接
        if (("http".equals(scheme) && serverPort != 80)
                || ("https".equals(scheme) && serverPort != 443)) {
            sb.append(":").append(serverPort);
        }
        sb.append("/api/auth/oauth2/callback");
        return sb.toString();
    }
}

