 81→     */
 82→    public ExamDetailResponse getExamDetail(Long examId, Long userId) {
 83→        Exam exam = getPublishedExamOrThrow(examId);
 84→        checkAccess(exam, userId);
 85→        return buildExamDetailResponse(exam, userId);
 86→    }
