167→    /**
168→     * 恢复进行中的考试：校验记录状态 → 返回题目列表
169→     */
170→    public ExamStartResponse resumeExam(Long examId, Long recordId, Long userId) {
171→        ExamRecord record = examRecordMapper.selectById(recordId);
172→        if (record == null) {
173→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
174→        }
175→        if (!record.getUserId().equals(userId) || !record.getExamId().equals(examId)) {
176→            throw new BizException(ErrorCode.FORBIDDEN);
177→        }
178→        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
179→            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
180→        }
181→
182→        // 查询本次考试抽中的题目
183→        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
184→                new LambdaQueryWrapper<ExamRecordQuestion>()
185→                        .eq(ExamRecordQuestion::getRecordId, recordId)
186→                        .orderByAsc(ExamRecordQuestion::getSortOrder));
187→        List<Long> questionIds = recordQuestions.stream()
188→                .map(ExamRecordQuestion::getQuestionId)
189→                .collect(Collectors.toList());
190→        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(questionIds)
191→                .stream()
192→                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
193→
194→        // 构建响应（不含正确答案和解析）
195→        ExamStartResponse response = new ExamStartResponse();
196→        response.setRecordId(recordId);
197→        List<ExamStartResponse.QuestionVO> questionVOs = new ArrayList<>(recordQuestions.size());
198→        for (ExamRecordQuestion rq : recordQuestions) {
199→            QuestionBank q = questionMap.get(rq.getQuestionId());
200→            if (q == null) continue;
201→            ExamStartResponse.QuestionVO vo = new ExamStartResponse.QuestionVO();
202→            vo.setId(q.getId());
203→            vo.setContent(q.getContent());
204→            vo.setOptionA(q.getOptionA());
205→            vo.setOptionB(q.getOptionB());
206→            vo.setOptionC(q.getOptionC());
207→            vo.setOptionD(q.getOptionD());
208→            vo.setSortOrder(rq.getSortOrder());
209→            questionVOs.add(vo);
210→        }
211→        response.setQuestions(questionVOs);
212→
213→        log.info("[lbl][Exam][RESUME] 恢复考试, userId={}, examId={}, recordId={}, questionCount={}",
214→                userId, examId, recordId, questionVOs.size());
215→
216→        return response;
217→    }
218→
219→    /**
220→     * 提交考试：评分 → 保存答题明细 → 更新记录
221→     */
222→    @Transactional(rollbackFor = Exception.class)
223→    public ExamSubmitResponse submitExam(ExamSubmitRequest req, Long userId) {
224→        // 1. 校验记录
225→        ExamRecord record = examRecordMapper.selectById(req.getRecordId());
226→        if (record == null) {
227→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
228→        }
229→        if (!record.getUserId().equals(userId)) {
230→            throw new BizException(ErrorCode.FORBIDDEN);
231→        }
232→        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
233→            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
234→        }
235→
236→        // 2. 判断是否超时
237→        Exam exam = examMapper.selectById(record.getExamId());
238→        RecordStatus status;
239→        if (exam.getTimeLimitMin() != null && exam.getTimeLimitMin() > 0
240→                && Duration.between(record.getStartTime(), LocalDateTime.now()).toMinutes() > exam.getTimeLimitMin()) {
241→            status = RecordStatus.TIMEOUT;
242→        } else {
243→            status = RecordStatus.SUBMITTED;
244→        }
245→
246→        // 3. 获取本次考试抽中的题目
247→        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
248→                new LambdaQueryWrapper<ExamRecordQuestion>()
249→                        .eq(ExamRecordQuestion::getRecordId, req.getRecordId()));
250→        List<Long> drawnQuestionIds = recordQuestions.stream()
251→                .map(ExamRecordQuestion::getQuestionId)
252→                .collect(Collectors.toList());
253→
254→        // 4. 查询题目详情
255→        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(drawnQuestionIds)
256→                .stream()
257→                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
258→
259→        // 5. 评分
260→        int totalQuestions = drawnQuestionIds.size();
261→        BigDecimal pointsPerQuestion = new BigDecimal(100)
262→                .divide(new BigDecimal(totalQuestions), 2, RoundingMode.HALF_UP);
263→        int correctCount = 0;
264→
265→        for (AnswerItem item : req.getAnswers()) {
266→            QuestionBank question = questionMap.get(item.getQuestionId());
267→            boolean isCorrect = question != null && item.getAnswer().equals(question.getCorrectAnswer());
268→            if (isCorrect) {
269→                correctCount++;
270→            }
271→
272→            // 保存答题明细
273→            AnswerDetail detail = AnswerDetail.builder()
274→                    .recordId(req.getRecordId())
275→                    .questionId(item.getQuestionId())
276→                    .userAnswer(item.getAnswer())
277→                    .isCorrect(isCorrect)
278→                    .build();
279→            answerDetailMapper.insert(detail);
280→        }
281→
282→        BigDecimal score = pointsPerQuestion.multiply(new BigDecimal(correctCount));
283→
284→        // 6. 更新考试记录
285→        record.setScore(score);
286→        record.setEndTime(LocalDateTime.now());
287→        record.setStatus(status);
288→        examRecordMapper.updateById(record);
289→
290→        log.info("[lbl][Exam][SUBMIT] 提交考试, userId={}, recordId={}, score={}, status={}",
291→                userId, req.getRecordId(), score, status.getValue());
292→
293→        // 7. 构建响应
294→        ExamSubmitResponse response = new ExamSubmitResponse();
295→        response.setScore(score);
296→        response.setStatus(status.getValue());
297→        return response;
298→    }
299→
300→    /**
301→     * 考生端-分页查询考试记录列表
302→     */
303→    public IPage<RecordDetailResponse> listRecords(Long userId, int page, int size) {
304→        Page<ExamRecord> recordPage = examRecordMapper.selectPage(
305→                new Page<>(page, size),
306→                new LambdaQueryWrapper<ExamRecord>()
307→                        .eq(ExamRecord::getUserId, userId)
308→                        .orderByDesc(ExamRecord::getCreatedAt));
309→
310→        // 批量获取考试标题
311→        Set<Long> examIds = recordPage.getRecords().stream()
312→                .map(ExamRecord::getExamId)
313→                .collect(Collectors.toSet());
314→        Map<Long, String> examTitleMap = examIds.isEmpty()
315→                ? Collections.emptyMap()
316→                : examMapper.selectBatchIds(examIds).stream()
317→                        .collect(Collectors.toMap(Exam::getId, Exam::getTitle));
318→
319→        // 转换
320→        Page<RecordDetailResponse> resultPage = new Page<>(page, size, recordPage.getTotal());
321→        resultPage.setRecords(recordPage.getRecords().stream()
322→                .map(r -> buildRecordSummary(r, examTitleMap.getOrDefault(r.getExamId(), "")))
323→                .collect(Collectors.toList()));
324→        return resultPage;
325→    }
