327→    /**
328→     * 考生端-查询考试记录详情（含答题明细）
329→     */
330→    public RecordDetailResponse getRecordDetail(Long recordId, Long userId) {
331→        ExamRecord record = examRecordMapper.selectById(recordId);
332→        if (record == null) {
333→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
334→        }
335→        if (!record.getUserId().equals(userId)) {
336→            throw new BizException(ErrorCode.FORBIDDEN);
337→        }
338→
339→        Exam exam = examMapper.selectById(record.getExamId());
340→        String examTitle = exam != null ? exam.getTitle() : "";
341→
342→        // 查询答题明细
343→        List<AnswerDetail> answerDetails = answerDetailMapper.selectList(
344→                new LambdaQueryWrapper<AnswerDetail>()
345→                        .eq(AnswerDetail::getRecordId, recordId));
346→
347→        // 查询对应题目
348→        List<Long> questionIds = answerDetails.stream()
349→                .map(AnswerDetail::getQuestionId)
350→                .collect(Collectors.toList());
351→        Map<Long, QuestionBank> questionMap = questionIds.isEmpty()
352→                ? Collections.emptyMap()
353→                : questionBankMapper.selectBatchIds(questionIds).stream()
354→                        .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
355→
356→        // 构建答题明细 VO
357→        boolean showAnswer = exam != null && Boolean.TRUE.equals(exam.getShowAnswer());
358→        boolean showAnalysis = exam != null && Boolean.TRUE.equals(exam.getShowAnalysis());
359→
360→        List<RecordDetailResponse.AnswerDetailVO> answerVOs = answerDetails.stream()
361→                .map(ad -> {
362→                    QuestionBank q = questionMap.get(ad.getQuestionId());
363→                    RecordDetailResponse.AnswerDetailVO vo = new RecordDetailResponse.AnswerDetailVO();
364→                    vo.setQuestionId(ad.getQuestionId());
365→                    vo.setUserAnswer(ad.getUserAnswer());
366→                    vo.setIsCorrect(ad.getIsCorrect());
367→                    if (q != null) {
368→                        vo.setContent(q.getContent());
369→                        vo.setOptionA(q.getOptionA());
370→                        vo.setOptionB(q.getOptionB());
371→                        vo.setOptionC(q.getOptionC());
372→                        vo.setOptionD(q.getOptionD());
373→                        vo.setCorrectAnswer(showAnswer ? q.getCorrectAnswer() : null);
374→                        vo.setAnalysis(showAnalysis ? q.getAnalysis() : null);
375→                    }
376→                    return vo;
377→                })
378→                .collect(Collectors.toList());
379→
380→        RecordDetailResponse response = buildRecordSummary(record, examTitle);
381→        response.setAnswers(answerVOs);
382→        return response;
383→    }
