385→    /**
386→     * 管理员查看考试记录详情（含答题明细，始终显示正确答案和解析）
387→     */
388→    public RecordDetailResponse getRecordDetailForAdmin(Long recordId) {
389→        ExamRecord record = examRecordMapper.selectById(recordId);
390→        if (record == null) {
391→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
392→        }
393→
394→        Exam exam = examMapper.selectById(record.getExamId());
