412→        List<RecordDetailResponse.AnswerDetailVO> answerVOs = answerDetails.stream()
413→                .map(ad -> {
414→                    QuestionBank q = questionMap.get(ad.getQuestionId());
415→                    RecordDetailResponse.AnswerDetailVO vo = new RecordDetailResponse.AnswerDetailVO();
416→                    vo.setQuestionId(ad.getQuestionId());
417→                    vo.setUserAnswer(ad.getUserAnswer());
418→                    vo.setIsCorrect(ad.getIsCorrect());
419→                    if (q != null) {
420→                        vo.setContent(q.getContent());
421→                        vo.setOptionA(q.getOptionA());
422→                        vo.setOptionB(q.getOptionB());
423→                        vo.setOptionC(q.getOptionC());
424→                        vo.setOptionD(q.getOptionD());
425→                        vo.setCorrectAnswer(q.getCorrectAnswer());
426→                        vo.setAnalysis(q.getAnalysis());
427→                    }
428→                    return vo;
429→                })
