453→    private void checkAccess(Exam exam, Long userId) {
454→        if (!hasAccess(exam, userId)) {
455→            throw new BizException(ErrorCode.FORBIDDEN);
456→        }
457→    }
458→
459→    /**
460→     * 判断用户是否有权访问该考试
461→     */
462→    private boolean hasAccess(Exam exam, Long userId) {
463→        if (exam.getAccessMode() == AccessMode.OPEN) {
464→            return true;
465→        }
466→        // 白名单模式：检查用户是否在白名单中
467→        long count = examWhitelistMapper.selectCount(
468→                new LambdaQueryWrapper<ExamWhitelist>()
469→                        .eq(ExamWhitelist::getExamId, exam.getId())
470→                        .eq(ExamWhitelist::getUserId, userId));
471→        return count > 0;
472→    }
473→
474→    /**
475→     * 统计用户在某考试下已完成的记录数（submitted + timeout）
476→     */
477→    private long countCompletedRecords(Long examId, Long userId) {
478→        return examRecordMapper.selectCount(
479→                new LambdaQueryWrapper<ExamRecord>()
480→                        .eq(ExamRecord::getExamId, examId)
481→                        .eq(ExamRecord::getUserId, userId)
482→                        .in(ExamRecord::getStatus, RecordStatus.SUBMITTED, RecordStatus.TIMEOUT));
483→    }
